window.addEventListener('message', (event) => {
   const { data } = event;

   switch (data.action) {
      case 'replaceContent':
         replaceContent(data.pattern, targetElement);
         break;
      case 'replaceImages':
         replaceImages(data.pattern, targetElement);
         break;
      case 'replaceColors':
         replaceColors(data.pattern);
         break;
      case 'init':
         window.Depicter.initAll();
         break;
      default:
         break;
   }
});
